RED.sidebar.meo = (function() {
    var content;
    var mainView;
    var wizardView;
    var deviceListContainer;
    // Device list mirrors the gateway (GET /api/v1/devices).
    var devices = [];

    function getApiUrl() {
        return RED.settings.theme("meo.apiUrl") || "http://localhost:7070";
    }

    function deviceUrl(deviceId) {
        return getApiUrl() + "/api/v1/devices/" + encodeURIComponent(deviceId);
    }

    function init() {
        content = $('<div id="red-ui-sidebar-meo"></div>');

        // ── Main view ──────────────────────────────────────────────
        mainView = $('<div class="meo-main-view"></div>').appendTo(content);

        // Devices section
        var deviceSection = $('<div class="meo-section"></div>').appendTo(mainView);
        var deviceHeader = $('<div class="meo-section-header"></div>').appendTo(deviceSection);
        $('<span class="meo-section-title"></span>').text(RED._("meo.devices.title")).appendTo(deviceHeader);
        var deviceBtns = $('<div class="meo-btn-group"></div>').appendTo(deviceHeader);
        $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-refresh"></i></button>')
            .attr('title', RED._("meo.devices.refresh"))
            .appendTo(deviceBtns)
            .on('click', loadDevices);
        $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-plus"></i></button>')
            .attr('title', RED._("meo.devices.add"))
            .appendTo(deviceBtns)
            .on('click', showWizard);
        deviceListContainer = $('<div class="meo-list-container"></div>').appendTo(deviceSection);
        loadDevices();

        // ── Provisioning wizard view (hidden by default) ───────────
        wizardView = $('<div class="meo-wizard-view"></div>').hide().appendTo(content);
        RED.sidebar.meo.provision.init({
            container: wizardView,
            getApiUrl: getApiUrl,
            onClose: hideWizard,
            onProvisioned: function() {
                // The device is persisted by now; the gateway list is the truth.
                loadDevices();
            }
        });

        RED.sidebar.addTab({
            id: "meo",
            label: "MEO",
            name: "MEO Dashboard",
            iconClass: "fa fa-tachometer",
            content: content,
            pinned: true,
            enableOnEdit: false
        });
    }

    // ── Devices ────────────────────────────────────────────────────

    function loadDevices() {
        deviceListContainer.empty();
        $('<div class="meo-loading"><i class="fa fa-spinner fa-spin"></i> </div>')
            .append($('<span></span>').text(RED._("meo.devices.loading")))
            .appendTo(deviceListContainer);
        $.ajax({
            url: getApiUrl() + "/api/v1/devices",
            method: "GET",
            dataType: "json",
            success: function(list) {
                devices = list || [];
                renderDeviceList();
            },
            error: function() {
                renderLoadError();
            }
        });
    }

    function renderLoadError() {
        deviceListContainer.empty();
        $('<div class="meo-error"></div>').text(RED._("meo.devices.loadError")).appendTo(deviceListContainer);
        $('<button class="red-ui-button red-ui-button-small"></button>')
            .text(RED._("meo.devices.retry"))
            .appendTo($('<div class="meo-list-footer"></div>').appendTo(deviceListContainer))
            .on('click', loadDevices);
    }

    function renderDeviceList() {
        deviceListContainer.empty();
        if (devices.length === 0) {
            $('<div class="meo-empty-note"></div>').text(RED._("meo.devices.empty")).appendTo(deviceListContainer);
            return;
        }
        devices.forEach(function(device) {
            renderDeviceRow(device);
        });
    }

    function renderDeviceRow(device) {
        var item = $('<div class="meo-item"></div>').appendTo(deviceListContainer);
        var info = $('<div class="meo-item-info"></div>').appendTo(item);
        $('<div class="meo-item-name"></div>').text(device.name || device.deviceId).appendTo(info);
        var meta = device.macAddress || '';
        if (device.model) { meta += ' · ' + device.model; }
        $('<div class="meo-item-meta"></div>').text(meta).appendTo(info);

        var actions = $('<div class="meo-btn-group"></div>').appendTo(item);
        $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-pencil"></i></button>')
            .attr('title', RED._("meo.devices.rename"))
            .appendTo(actions)
            .on('click', function() {
                startRename(item, device);
            });
        var deleteBtn = $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-trash"></i></button>')
            .attr('title', RED._("meo.devices.delete"))
            .appendTo(actions)
            .on('click', function() {
                // Two-click confirm: first click arms the button, second deletes.
                if (!deleteBtn.hasClass('meo-confirm')) {
                    deleteBtn.addClass('meo-confirm').attr('title', RED._("meo.devices.confirmDelete"));
                    setTimeout(function() {
                        deleteBtn.removeClass('meo-confirm').attr('title', RED._("meo.devices.delete"));
                    }, 3000);
                    return;
                }
                deleteDevice(device);
            });
    }

    function startRename(item, device) {
        var info = item.children('.meo-item-info');
        var actions = item.children('.meo-btn-group');
        info.hide();
        actions.hide();

        var form = $('<div class="meo-rename-form"></div>').appendTo(item);
        var input = $('<input type="text" class="meo-rename-input">')
            .val(device.name || "")
            .appendTo(form);
        var formBtns = $('<div class="meo-btn-group"></div>').appendTo(form);
        $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-check"></i></button>')
            .attr('title', RED._("meo.devices.save"))
            .appendTo(formBtns)
            .on('click', save);
        $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-times"></i></button>')
            .attr('title', RED._("meo.devices.cancel"))
            .appendTo(formBtns)
            .on('click', cancel);
        input.on('keydown', function(evt) {
            if (evt.key === "Enter") { save(); }
            else if (evt.key === "Escape") { cancel(); }
        });
        input.trigger('focus').trigger('select');

        function save() {
            var name = input.val().trim();
            if (!name || name === device.name) {
                cancel();
                return;
            }
            $.ajax({
                url: deviceUrl(device.deviceId),
                method: "PUT",
                contentType: "application/json",
                dataType: "json",
                // The gateway overwrites all user-metadata fields from the
                // body, so carry the untouched ones through.
                data: JSON.stringify({
                    name: name,
                    description: device.description,
                    deviceType: device.deviceType
                }),
                success: function() {
                    loadDevices();
                },
                error: function() {
                    actionFailed();
                    cancel();
                }
            });
        }

        function cancel() {
            form.remove();
            info.show();
            actions.show();
        }
    }

    function deleteDevice(device) {
        $.ajax({
            url: deviceUrl(device.deviceId),
            method: "DELETE",
            success: function() {
                loadDevices();
            },
            error: function() {
                actionFailed();
            }
        });
    }

    function actionFailed() {
        RED.notify(RED._("meo.devices.actionError"), "error");
    }

    // ── Wizard ─────────────────────────────────────────────────────

    function showWizard() {
        mainView.hide();
        wizardView.show();
        RED.sidebar.meo.provision.open();
    }

    function hideWizard() {
        wizardView.hide();
        mainView.show();
    }

    return {
        init: init
    };
})();
